func (cs callSet) Add(call *Call) {
	key := callSetKey{call.receiver, call.method}

	cs.expectedMu.Lock()
	defer cs.expectedMu.Unlock()

	m := cs.expected
	if call.exhausted() {
		m = cs.exhausted
	}
	if cs.allowOverride {
		m[key] = make([]*Call, 0)
	}

	m[key] = append(m[key], call)
}

